noncompliant:
// C++14 attribute
[[deprecated]] // Noncompliant
void fun();

// GNU attribute
__attribute__((deprecated)) // Noncompliant
void fun();

// Microsoft attribute
__declspec(deprecated) // Noncompliant
void fun();

compliant:
// Remove deprecated functions entirely
// [[deprecated]] void old_fun(); // Remove this line
void new_improved_fun() {
    // Updated implementation
}

// Or provide migration path in comments
void modern_function() {
    // Replaces the deprecated old_function()
    // New implementation here
}
